from decimal import Decimal, InvalidOperation

vals = ['10', 'x', '3.5']
for v in vals:
    try:
        m = Decimal(v).quantize(Decimal('0.01'))
        print('ok', m)
    except InvalidOperation:
        print('reject', v, 'motivo=cast_monto')
